class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int[] nums = new int[n];
        int sum = 0;
        for (int i = 0; i < n; i++) {
            if (i == index) {
                nums[i] = maxSum - sum;
            } else {
                nums[i] = sum + 1;
                sum += nums[i];
            }
        }
        return nums[index];
    }
}
